code = """import json
import re
from collections import defaultdict

# Load California patents data
cal_pats_file = 'file_storage/functions.query_db:80.json'
with open(cal_pats_file, 'r') as f:
    cal_pats = json.load(f)

# Build comprehensive mapping of California publication numbers to their CPC subclassescal_pub_to_cpc = {}
cal_pub_numbers = set()

for patent in cal_pats:
    patents_info = patent['Patents_info']
    
    # Extract publication number multiple ways
    pub_num = None
    for pattern in [r'pub\. number ([A-Z0-9-]+)', r'publication number ([A-Z0-9-]+)', r'publication no\. ([A-Z0-9-]+)']:
        match = re.search(pattern, patents_info)
        if match:
            pub_num = match.group(1)
            break
    
    if not pub_num:
        continue
        
    cal_pub_numbers.add(pub_num)
    
    # Get primary CPC codes (inventive=true)
    primary_cpcs = []
    if patent.get('cpc'):
        try:
            cpc_data = json.loads(patent['cpc'])
            for cpc in cpc_data:
                if cpc.get('inventive', False):
                    code = cpc['code']
                    # Use subclass level (before slash)
                    subclass = code.split('/')[0] if '/' in code else code[:4]
                    if subclass and len(subclass) >= 3:
                        primary_cpcs.append(subclass)
            # Deduplicate
            cal_pub_to_cpc[pub_num] = list(dict.fromkeys(primary_cpcs))
        except:
            cal_pub_to_cpc[pub_num] = []
    else:
        cal_pub_to_cpc[pub_num] = []

result = {
    'total_california_pubs': len(cal_pub_numbers),
    'sample_pub_numbers': list(cal_pub_numbers)[:10],
    'sample_cpc_mapping': {k: v for k, v in list(cal_pub_to_cpc.items())[:5] if v}
}

print('__RESULT__:')
print(json.dumps(result))"""

